# 3. Express API with Security Issues
echo "3️⃣  Creating Express API Example..."
mkdir -p "03-express-api"
cd "03-express-api"

cat > server.js << 'EOF'
const express = require('express');
const app = express();

app.use(express.json());

// In-memory "database" - not secure for production
let users = [
    { id: 1, username: 'admin', password: 'password123', role: 'admin' },
    { id: 2, username: 'user', password: 'user123', role: 'user' }
];

// SECURITY ISSUE: No authentication
app.get('/users', (req, res) => {
    res.json(users);
});

// SECURITY ISSUE: SQL injection vulnerable (simulated)
app.get('/users/:id', (req, res) => {
    const id = req.params.id;
    // Simulated vulnerable query
    const user = users.find(u => u.id == id);
    res.json(user);
});

// SECURITY ISSUE: No input validation
app.post('/users', (req, res) => {
    const { username, password, role } = req.body;
    const newUser = {
        id: users.length + 1,
        username,
        password, // SECURITY ISSUE: Plain text password
        role
    };
    users.push(newUser);
    res.json(newUser);
});

// SECURITY ISSUE: No rate limiting
app.post('/login', (req, res) => {
    const { username, password } = req.body;
    const user = users.find(u => u.username === username && u.password === password);
    
    if (user) {
        // SECURITY ISSUE: No JWT, just sending user data
        res.json({ success: true, user });
    } else {
        res.status(401).json({ success: false, message: 'Invalid credentials' });
    }
});

// TODO: Add CORS configuration
// TODO: Add helmet for security headers
// TODO: Add input validation middleware
// TODO: Add rate limiting
// TODO: Add proper error handling

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
});
EOF

