#!/usr/bin/env python3
"""
Data processor with various issues for Codestral to fix
"""

import json
import csv

# TODO: Add proper error handling
# TODO: Add type hints
# TODO: Add docstrings
# FIXME: No input validation

def read_json_file(filename):
    # FIXME: No error handling for file operations
    with open(filename, 'r') as f:
        return json.load(f)

def write_csv_file(data, filename):
    # TODO: Add proper CSV handling
    with open(filename, 'w') as f:
        writer = csv.writer(f)
        for row in data:
            writer.writerow(row)

def process_data(data):
    # FIXME: Assumes data structure without validation
    processed = []
    for item in data:
        # TODO: Add data validation
        processed_item = {
            'id': item['id'],
            'name': item['name'].upper(),  # FIXME: No null check
            'value': item['value'] * 2
        }
        processed.append(processed_item)
    return processed

def main():
    # TODO: Add command line argument parsing
    # TODO: Add logging
    
    try:
        data = read_json_file('input.json')
        processed = process_data(data)
        write_csv_file(processed, 'output.csv')
        print("Processing complete!")
    except Exception as e:
        print(f"Error: {e}")  # FIXME: Poor error handling

if __name__ == "__main__":
    main()
EOF

